package online.yudream.base.infra.platform.wiki.impl;
import lombok.RequiredArgsConstructor; import online.yudream.base.domain.platform.wiki.aggregate.WikiNode; import online.yudream.base.domain.platform.wiki.repo.WikiNodeRepo; import online.yudream.base.domain.shared.IdGenerator; import online.yudream.base.infra.platform.wiki.dataobj.WikiNodeDO; import online.yudream.base.infra.platform.wiki.mapper.WikiInfraMapper; import org.springframework.data.domain.Sort; import org.springframework.data.mongodb.core.MongoTemplate; import org.springframework.data.mongodb.core.query.Criteria; import org.springframework.data.mongodb.core.query.Query; import org.springframework.stereotype.Service; import java.time.LocalDateTime; import java.util.*;
@Service @RequiredArgsConstructor public class WikiNodeRepoImpl implements WikiNodeRepo {private final MongoTemplate mongo;private final IdGenerator ids;public WikiNode save(WikiNode n){WikiNodeDO d=WikiInfraMapper.node(n);if(d.getId()==null){d.setId(ids.nextId());d.setCreateTime(LocalDateTime.now());}d.setUpdateTime(LocalDateTime.now());return WikiInfraMapper.node(mongo.save(d));}public Optional<WikiNode> findById(Long id){return Optional.ofNullable(WikiInfraMapper.node(mongo.findById(id,WikiNodeDO.class)));}public List<WikiNode> findBySpaceId(Long id){return mongo.find(Query.query(Criteria.where("spaceId").is(id)).with(Sort.by("sort","createTime")),WikiNodeDO.class).stream().map(WikiInfraMapper::node).toList();}public void deleteById(Long id){mongo.remove(Query.query(Criteria.where("id").is(id)),WikiNodeDO.class);}}
